import React, { useEffect, useRef, useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";
import api from "../api";

function AddEditItem() {
  const locationHook = useLocation();
  const navigate = useNavigate();
  const editItem = locationHook.state?.editItem;
  const presetStatus = locationHook.state?.presetStatus;
  const initialValues = locationHook.state?.initialValues || {};
  const [form, setForm] = useState({
    title: "",
    description: "",
    category: "",
    location: "",
    date: "",
    status: presetStatus || "LOST",
    contactInfo: ""
  });
  const [message, setMessage] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [referenceImages, setReferenceImages] = useState([]);
  const [isDragActive, setIsDragActive] = useState(false);
  const fileInputRef = useRef(null);

  useEffect(() => {
    if (editItem) {
      setForm({
        title: editItem.title || "",
        description: editItem.description || "",
        category: editItem.category || "",
        location: editItem.location || "",
        date: editItem.date || "",
        status: editItem.status || "LOST",
        contactInfo: editItem.contactInfo || ""
      });

      try {
        const parsedImages = editItem.referenceImages
          ? JSON.parse(editItem.referenceImages).map((image, index) => ({
              name: `reference-${index + 1}.png`,
              dataUrl: image
            }))
          : [];
        setReferenceImages(parsedImages);
      } catch (error) {
        setReferenceImages([]);
      }
      return;
    }

    setForm((prev) => ({
      ...prev,
      title: initialValues.title || "",
      description: initialValues.description || "",
      category: initialValues.category || "",
      location: initialValues.location || "",
      status: presetStatus || prev.status
    }));
  }, [editItem, initialValues, presetStatus]);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const compressImage = (file) =>
    new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => {
        const image = new Image();
        image.onload = () => {
          const maxDimension = 1200;
          let { width, height } = image;

          if (width > height && width > maxDimension) {
            height = Math.round((height * maxDimension) / width);
            width = maxDimension;
          } else if (height >= width && height > maxDimension) {
            width = Math.round((width * maxDimension) / height);
            height = maxDimension;
          }

          const canvas = document.createElement("canvas");
          canvas.width = width;
          canvas.height = height;
          const context = canvas.getContext("2d");
          context.drawImage(image, 0, 0, width, height);

          const compressedDataUrl = canvas.toDataURL("image/jpeg", 0.72);
          resolve({
            name: file.name,
            dataUrl: compressedDataUrl
          });
        };
        image.onerror = reject;
        image.src = reader.result;
      };
      reader.onerror = reject;
      reader.readAsDataURL(file);
    });

  const filesToBase64 = async (files) => {
    const imageFiles = files.filter((file) => file.type.startsWith("image/"));
    const readers = imageFiles.map((file) => compressImage(file));
    return Promise.all(readers);
  };

  const handleFiles = async (fileList) => {
    const convertedImages = await filesToBase64(Array.from(fileList));
    setReferenceImages((prev) => [...prev, ...convertedImages]);
  };

  const handleDrop = async (e) => {
    e.preventDefault();
    setIsDragActive(false);
    await handleFiles(e.dataTransfer.files);
  };

  const handleFileSelect = async (e) => {
    await handleFiles(e.target.files);
  };

  const removeImage = (indexToRemove) => {
    setReferenceImages((prev) => prev.filter((_, index) => index !== indexToRemove));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMessage("");
    const userId = localStorage.getItem("userId");
    if (!userId) {
      setMessage("Please login first.");
      return;
    }
    setIsLoading(true);
    try {
      const payload = {
        ...form,
        imageUrl: referenceImages[0]?.dataUrl || "",
        referenceImages: JSON.stringify(referenceImages.map((image) => image.dataUrl))
      };
      const requesterRole = localStorage.getItem("role") || "USER";
      let response;

      if (editItem) {
        response = await api.put(
          `/items/${editItem.id}?requesterId=${userId}&role=${requesterRole}`,
          payload
        );
        setMessage(`Item updated successfully with ID: ${response.data.id}`);
      } else {
        response = await api.post(`/items?userId=${userId}`, payload);
        setMessage(`Item saved with ID: ${response.data.id}`);
      }

      setForm({
        title: "",
        description: "",
        category: "",
        location: "",
        date: "",
        status: "LOST",
        contactInfo: ""
      });
      setReferenceImages([]);
      setTimeout(() => navigate("/dashboard"), 800);
    } catch (error) {
      const msg = error.response?.data?.message || "Item save failed. Try smaller images.";
      setMessage(msg);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="panel">
      <h3>Add / Edit Item</h3>
      <p className="helper-text">
        Use this form for both lost and found entries. Images are automatically resized for smooth upload.
      </p>
      <form className="item-form" onSubmit={handleSubmit}>
        <input name="title" value={form.title} placeholder="Title" onChange={handleChange} required />
        <input name="description" value={form.description} placeholder="Description" onChange={handleChange} />
        <input name="category" value={form.category} placeholder="Category" onChange={handleChange} required />
        <input name="location" value={form.location} placeholder="Location" onChange={handleChange} required />
        <input name="date" value={form.date} type="date" onChange={handleChange} />
        <select name="status" value={form.status} onChange={handleChange}>
          <option value="LOST">LOST</option>
          <option value="FOUND">FOUND</option>
          <option value="CLAIMED">CLAIMED</option>
          <option value="RETURNED">RETURNED</option>
        </select>
        <input name="contactInfo" value={form.contactInfo} placeholder="Contact Info" onChange={handleChange} />
        <div
          className={`upload-dropzone ${isDragActive ? "drag-active" : ""}`}
          onDragOver={(e) => {
            e.preventDefault();
            setIsDragActive(true);
          }}
          onDragLeave={() => setIsDragActive(false)}
          onDrop={handleDrop}
          onClick={() => fileInputRef.current?.click()}
        >
          <input
            ref={fileInputRef}
            className="hidden-file-input"
            type="file"
            accept="image/*"
            multiple
            onChange={handleFileSelect}
          />
          <p className="upload-title">Reference Image</p>
          <p className="helper-text">Drag and drop one or more images here, or click to browse.</p>
        </div>
        {referenceImages.length > 0 ? (
          <div className="preview-grid">
            {referenceImages.map((image, index) => (
              <div className="preview-card" key={`${image.name}-${index}`}>
                <img src={image.dataUrl} alt={image.name} />
                <div className="preview-card-footer">
                  <span>{image.name}</span>
                  <button type="button" className="ghost-btn" onClick={() => removeImage(index)}>
                    Remove
                  </button>
                </div>
              </div>
            ))}
          </div>
        ) : null}
        <button type="submit" disabled={isLoading}>
          {isLoading ? "Saving..." : editItem ? "Update Item" : "Save Item"}
        </button>
      </form>
      {message ? <p className={message.includes("saved") ? "success-text" : "error-text"}>{message}</p> : null}
    </div>
  );
}

export default AddEditItem;
